  { id: '2', name: 'Jasprit Bumrah', age: 30, role: 'Bowler', battingRating: 15, bowlingRating: 96, fitness: 92, value: 12000000, salary: 180000, image: 'https://picsum.photos/seed/bumrah/200/200' },
  { id: '3', name: 'Ben Stokes', age: 32, role: 'All-Rounder', battingRating: 88, bowlingRating: 85, fitness: 89, value: 11000000, salary: 175000, image: 'https://picsum.photos/seed/stokes/200/200' },
  { id: '4', name: 'Quinton de Kock', age: 31, role: 'Wicket-Keeper', battingRating: 86, bowlingRating: 5, fitness: 90, value: 9000000, salary: 150000, image: 'https://picsum.photos/seed/kock/200/200' },
  { id: '5', name: 'Rashid Khan', age: 25, role: 'Bowler', battingRating: 30, bowlingRating: 95, fitness: 95, value: 10000000, salary: 160000, image: 'https://picsum.photos/seed/rashid/200/200' },
