export const MARKET_PLAYERS: Player[] = [
  { id: 'm1', name: 'Shaheen Afridi', age: 23, role: 'Bowler', battingRating: 20, bowlingRating: 93, fitness: 94, value: 9500000, salary: 140000, image: 'https://picsum.photos/seed/shaheen/200/200' },
  { id: 'm2', name: 'Travis Head', age: 30, role: 'Batsman', battingRating: 89, bowlingRating: 45, fitness: 88, value: 8500000, salary: 130000, image: 'https://picsum.photos/seed/head/200/200' },
  { id: 'm3', name: 'Sam Curran', age: 25, role: 'All-Rounder', battingRating: 75, bowlingRating: 82, fitness: 91, value: 7000000, salary: 110000, image: 'https://picsum.photos/seed/curran/200/200' },
];

import { GoogleGenAI, Type } from "@google/genai";
import { Player, Team, MatchState } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAITacticalAdvice = async (team: Team) => {
  try {
    const squadInfo = team.squad.map(p => `${p.name} (${p.role}, Rating: ${p.battingRating}/${p.bowlingRating})`).join(", ");
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze this cricket team and provide tactical advice: ${team.name}. Squad: ${squadInfo}. Budget: ${team.budget}. Provide scouting recommendations, a tactical tip, and a player of the month.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            scoutingReport: { type: Type.STRING },
            tacticalTip: { type: Type.STRING },
            playerOfTheMonthSuggestion: { type: Type.STRING }
          },
          required: ["scoutingReport", "tacticalTip", "playerOfTheMonthSuggestion"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("AI Advice Error:", error);
    return {
      scoutingReport: "Focus on strengthening the middle-order batting.",
      tacticalTip: "Try utilizing your spinners during the middle overs to choke the run rate.",
      playerOfTheMonthSuggestion: team.squad[0]?.name || "Your Captain"
    };
  }
};

export const getMatchNarration = async (matchState: MatchState, event: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are a cricket commentator. Narrate a specific match event: "${event}". Current Score: ${matchState.score}/${matchState.wickets} in ${matchState.overs}.${matchState.balls} overs. Keep it exciting and under 50 words.`
    });
    return response.text;
  } catch (error) {
    return "What a fantastic delivery! The crowd is going wild!";
  }
};

import React from 'react';
import { Player } from '../types';

interface PlayerCardProps {
  player: Player;
  onAction?: (player: Player) => void;
  actionLabel?: string;
}

const PlayerCard: React.FC<PlayerCardProps> = ({ player, onAction, actionLabel }) => {
  const getRoleColor = (role: string) => {
    switch (role) {
      case 'Batsman': return 'bg-blue-500';
      case 'Bowler': return 'bg-red-500';
      case 'All-Rounder': return 'bg-green-500';
      case 'Wicket-Keeper': return 'bg-yellow-500';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div className="bg-slate-800 rounded-xl overflow-hidden border border-slate-700 shadow-lg hover:border-blue-500 transition-all">
      <div className="relative h-40">
        <img src={player.image} alt={player.name} className="w-full h-full object-cover opacity-80" />
        <div className={`absolute top-2 right-2 px-2 py-1 rounded text-[10px] font-bold uppercase text-white ${getRoleColor(player.role)}`}>
          {player.role}
        </div>
      </div>
      <div className="p-4">
        <h3 className="text-lg font-bold truncate">{player.name}</h3>
        <div className="flex justify-between mt-2 text-sm text-slate-400">
          <span>Age: {player.age}</span>
          <span className="text-white font-medium">Value: ${(player.value / 1000000).toFixed(1)}M</span>
        </div>

        <div className="mt-4 space-y-2">
          <div className="flex items-center justify-between text-xs">
            <span>Batting</span>
            <div className="w-2/3 bg-slate-700 h-1.5 rounded-full overflow-hidden">
              <div className="bg-blue-400 h-full" style={{ width: `${player.battingRating}%` }}></div>
            </div>
            <span className="w-6 text-right">{player.battingRating}</span>
          </div>
          <div className="flex items-center justify-between text-xs">
            <span>Bowling</span>
            <div className="w-2/3 bg-slate-700 h-1.5 rounded-full overflow-hidden">
              <div className="bg-red-400 h-full" style={{ width: `${player.bowlingRating}%` }}></div>
            </div>
            <span className="w-6 text-right">{player.bowlingRating}</span>
          </div>
          <div className="flex items-center justify-between text-xs">
            <span>Fitness</span>
            <div className="w-2/3 bg-slate-700 h-1.5 rounded-full overflow-hidden">
              <div className="bg-green-400 h-full" style={{ width: `${player.fitness}%` }}></div>
            </div>
            <span className="w-6 text-right">{player.fitness}</span>
          </div>
        </div>

        {onAction && actionLabel && (
          <button
            onClick={() => onAction(player)}
            className="w-full mt-4 bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded transition-colors text-sm"
          >
            {actionLabel}
          </button>
        )}
      </div>
    </div>
  );
};

export default PlayerCard;

import React, { useState, useEffect, useCallback } from 'react';
import { LayoutDashboard, Users, ShoppingBag, Trophy, BarChart3, Menu, X, Info } from 'lucide-react';
import { View, Team, Player, MatchState, AIAdvice } from './types';
import { INITIAL_TEAM, MARKET_PLAYERS } from './constants';
import PlayerCard from './components/PlayerCard';
import { getAITacticalAdvice, getMatchNarration } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [team, setTeam] = useState<Team>(INITIAL_TEAM);
  const [market, setMarket] = useState<Player[]>(MARKET_PLAYERS);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [aiAdvice, setAIAdvice] = useState<AIAdvice | null>(null);
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);

  // Match State
  const [matchInProgress, setMatchInProgress] = useState(false);
  const [matchState, setMatchState] = useState<MatchState>({ score: 0, wickets: 0, overs: 0, balls: 0, innings: 1 });
  const [matchLog, setMatchLog] = useState<string[]>([]);

  // Initialize AI Advice
  useEffect(() => {
    const fetchAdvice = async () => {
      setIsLoadingAdvice(true);
      const advice = await getAITacticalAdvice(team);
      setAIAdvice(advice);
      setIsLoadingAdvice(false);
    };
    fetchAdvice();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleBuyPlayer = (player: Player) => {
    if (team.budget >= player.value) {
      setTeam(prev => ({
        ...prev,
        budget: prev.budget - player.value,
        squad: [...prev.squad, player]
      }));
      setMarket(prev => prev.filter(p => p.id !== player.id));
      alert(`Success! ${player.name} has joined ${team.name}`);
    } else {
      alert("Insufficient funds in the transfer budget!");
    }
  };

  const handleSellPlayer = (player: Player) => {
    setTeam(prev => ({
      ...prev,
      budget: prev.budget + (player.value * 0.8),
      squad: prev.squad.filter(p => p.id !== player.id)
    }));
    setMarket(prev => [...prev, { ...player, id: `m-${Date.now()}` }]);
    alert(`${player.name} has been sold.`);
  };

  const simulateBall = useCallback(async () => {
    if (!matchInProgress) return;

    setMatchState(prev => {
      const isOut = Math.random() < 0.05;
      const runsOptions = [0, 1, 2, 3, 4, 6];
      const runs = isOut ? 0 : runsOptions[Math.floor(Math.random() * runsOptions.length)];

      let newBalls = prev.balls + 1;
      let newOvers = prev.overs;
      if (newBalls === 6) {
        newBalls = 0;
        newOvers += 1;
      }

      const newWickets = isOut ? prev.wickets + 1 : prev.wickets;
      const newScore = prev.score + runs;

      // Handle match end
      if (newWickets >= 10 || newOvers >= 5) {
        setMatchInProgress(false);
        setTeam(t => ({ ...t, wins: t.wins + (newScore > 50 ? 1 : 0), losses: t.losses + (newScore > 50 ? 0 : 1) }));
      }

      // Generate AI Narration every over or event
      if (isOut || runs === 6 || runs === 4 || newBalls === 0) {
        const eventStr = isOut ? "A WICKET!" : runs === 6 ? "A MASSIVE SIX!" : runs === 4 ? "Beautiful boundary!" : "End of the over.";
        getMatchNarration(prev, eventStr).then(narration => {
          setMatchLog(log => [narration, ...log].slice(0, 10));
        });
      }

      return {
        ...prev,
        score: newScore,
        wickets: newWickets,
        overs: newOvers,
        balls: newBalls
      };
    });
  }, [matchInProgress]);

  useEffect(() => {
    let interval: number;
    if (matchInProgress) {
      interval = window.setInterval(simulateBall, 1000);
    }
    return () => clearInterval(interval);
  }, [matchInProgress, simulateBall]);

  const startMatch = () => {
    setMatchState({ score: 0, wickets: 0, overs: 0, balls: 0, innings: 1 });
    setMatchLog(["The players are coming onto the field! Match is about to start."]);
    setMatchInProgress(true);
    setCurrentView(View.MATCH);
  };

  const NavItem = ({ icon: Icon, label, view }: { icon: any, label: string, view: View }) => (
    <button
      onClick={() => setCurrentView(view)}
      className={`flex items-center space-x-3 w-full px-4 py-3 rounded-lg transition-colors ${
        currentView === view ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
      }`}
    >
      <Icon size={20} />
      <span className={`${!isSidebarOpen && 'hidden'} font-medium`}>{label}</span>
    </button>
  );

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden text-slate-100">
      {/* Sidebar */}
      <aside className={`bg-slate-900 border-r border-slate-800 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'}`}>
        <div className="p-6 flex items-center justify-between">
          <div className={`flex items-center space-x-2 ${!isSidebarOpen && 'hidden'}`}>
            <Trophy className="text-yellow-500" />
            <span className="font-bold text-xl tracking-tight">CM26</span>
          </div>
          <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-1 hover:bg-slate-800 rounded">
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-2 mt-4">
          <NavItem icon={LayoutDashboard} label="Dashboard" view={View.DASHBOARD} />
          <NavItem icon={Users} label="My Squad" view={View.SQUAD} />
          <NavItem icon={ShoppingBag} label="Transfer Market" view={View.MARKET} />
          <NavItem icon={BarChart3} label="Live Match" view={View.MATCH} />
        </nav>

        <div className="p-4 bg-slate-800/50 m-4 rounded-lg">
          <div className={`${!isSidebarOpen && 'hidden'}`}>
            <p className="text-[10px] text-slate-500 uppercase font-bold mb-1">Budget</p>
            <p className="text-lg font-bold text-green-400">${(team.budget / 1000000).toFixed(1)}M</p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-3xl font-bold">{team.name}</h1>
            <p className="text-slate-400">{currentView.charAt(0) + currentView.slice(1).toLowerCase()}</p>
          </div>
          <div className="flex space-x-4">
             <button 
              onClick={startMatch}
              className="bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-6 rounded-full shadow-lg shadow-green-900/20 transition-all flex items-center space-x-2"
             >
               <Trophy size={18} />
               <span>Next Match</span>
             </button>
          </div>
        </header>

        {currentView === View.DASHBOARD && (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 flex items-center space-x-4">
                <div className="p-3 bg-blue-500/10 rounded-xl text-blue-500"><Users /></div>
                <div>
                  <p className="text-slate-500 text-sm">Squad Size</p>
                  <p className="text-2xl font-bold">{team.squad.length}</p>
                </div>
              </div>
              <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 flex items-center space-x-4">
                <div className="p-3 bg-green-500/10 rounded-xl text-green-500"><Trophy /></div>
                <div>
                  <p className="text-slate-500 text-sm">Wins</p>
                  <p className="text-2xl font-bold">{team.wins}</p>
                </div>
              </div>
              <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 flex items-center space-x-4">
                <div className="p-3 bg-red-500/10 rounded-xl text-red-500"><BarChart3 /></div>
                <div>
                  <p className="text-slate-500 text-sm">Win Rate</p>
                  <p className="text-2xl font-bold">
                    {team.wins + team.losses === 0 ? '0%' : `${Math.round((team.wins / (team.wins + team.losses)) * 100)}%`}
                  </p>
                </div>
              </div>
            </div>

            {/* AI Insights and Chart */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800">
                <div className="flex items-center space-x-2 mb-6">
                  <div className="p-2 bg-purple-500/20 rounded text-purple-400">
                    <Info size={20} />
                  </div>
                  <h2 className="text-xl font-bold">AI Strategic Analysis</h2>
                </div>
                {isLoadingAdvice ? (
                  <div className="animate-pulse space-y-4">
                    <div className="h-4 bg-slate-800 rounded w-3/4"></div>
                    <div className="h-4 bg-slate-800 rounded w-5/6"></div>
                    <div className="h-4 bg-slate-800 rounded w-2/3"></div>
                  </div>
                ) : aiAdvice ? (
                  <div className="space-y-6">
                    <div>
                      <h4 className="text-sm font-bold text-slate-500 uppercase mb-2">Scouting Report</h4>
                      <p className="text-slate-300 leading-relaxed">{aiAdvice.scoutingReport}</p>
                    </div>
                    <div>
                      <h4 className="text-sm font-bold text-slate-500 uppercase mb-2">Tactical Tip</h4>
                      <div className="bg-blue-900/20 border border-blue-500/20 p-4 rounded-xl text-blue-300">
                        {aiAdvice.tacticalTip}
                      </div>
                    </div>
                    <div>
                      <h4 className="text-sm font-bold text-slate-500 uppercase mb-2">Player to Watch</h4>
                      <div className="flex items-center space-x-3">
                        <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center text-xs font-bold text-blue-400 border border-slate-700">
                          {aiAdvice.playerOfTheMonthSuggestion[0]}
                        </div>
                        <p className="font-medium">{aiAdvice.playerOfTheMonthSuggestion}</p>
                      </div>
                    </div>
                  </div>
                ) : (
                  <p className="text-slate-500">Analysis unavailable. Check your connection.</p>
                )}
              </div>

              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800">
                <h2 className="text-xl font-bold mb-6">Squad Batting Ratings</h2>
                <div className="h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={team.squad}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                      <XAxis dataKey="name" stroke="#94a3b8" fontSize={10} tick={{ fill: '#94a3b8' }} />
                      <YAxis stroke="#94a3b8" fontSize={12} />
                      <Tooltip 
                        contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '8px' }}
                        itemStyle={{ color: '#fff' }}
                      />
                      <Bar dataKey="battingRating" radius={[4, 4, 0, 0]}>
                        {team.squad.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={entry.battingRating > 85 ? '#3b82f6' : '#64748b'} />
                        ))}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>
            </div>
          </div>
        )}

        {currentView === View.SQUAD && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-in slide-in-from-bottom-4 duration-500">
            {team.squad.map(player => (
              <PlayerCard 
                key={player.id} 
                player={player} 
                onAction={handleSellPlayer} 
                actionLabel="List for Transfer" 
              />
            ))}
          </div>
        )}

        {currentView === View.MARKET && (
          <div className="space-y-8">
            <div className="bg-blue-600/10 border border-blue-500/30 p-6 rounded-2xl flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-blue-400">Transfer Market is Open</h2>
                <p className="text-slate-400">Scout and sign world-class talent to bolster your squad.</p>
              </div>
              <div className="text-right">
                <p className="text-xs text-slate-500 uppercase font-bold">Available Funds</p>
                <p className="text-2xl font-bold text-green-400">${(team.budget / 1000000).toFixed(1)}M</p>
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-in slide-in-from-bottom-4 duration-500">
              {market.map(player => (
                <PlayerCard 
                  key={player.id} 
                  player={player} 
                  onAction={handleBuyPlayer} 
                  actionLabel={`Sign for $${(player.value / 1000000).toFixed(1)}M`} 
                />
              ))}
            </div>
          </div>
        )}

        {currentView === View.MATCH && (
          <div className="max-w-4xl mx-auto space-y-8 animate-in zoom-in-95 duration-500">
            <div className="bg-slate-900 rounded-3xl border border-slate-800 overflow-hidden shadow-2xl">
              <div className="bg-gradient-to-r from-blue-900 to-indigo-900 p-8 text-center">
                <div className="flex justify-around items-center mb-6">
                  <div className="flex flex-col items-center">
                    <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-2">
                       <Trophy className="text-yellow-400" />
                    </div>
                    <span className="font-bold">{team.name}</span>
                  </div>
                  <div className="text-4xl font-black px-6 py-2 bg-black/30 rounded-xl">VS</div>
                  <div className="flex flex-col items-center">
                    <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-2">
                       <Users className="text-slate-400" />
                    </div>
                    <span className="font-bold text-slate-300">World XI</span>
                  </div>
                </div>

                <div className="space-y-2">
                  <h2 className="text-6xl font-black tabular-nums tracking-tighter">
                    {matchState.score}<span className="text-indigo-300">/</span>{matchState.wickets}
                  </h2>
                  <p className="text-indigo-200 text-xl font-medium">
                    Overs: {matchState.overs}.{matchState.balls}
                  </p>
                </div>
              </div>

              <div className="p-8 space-y-6 bg-slate-950/50">
                <div className="flex justify-center space-x-4">
                  {!matchInProgress && matchState.overs === 0 && (
                     <button onClick={startMatch} className="px-8 py-3 bg-blue-600 rounded-full font-bold shadow-lg">Toss & Play</button>
                  )}
                  {matchInProgress && (
                    <div className="flex items-center space-x-2 text-green-400">
                       <div className="w-2 h-2 bg-green-500 rounded-full animate-ping"></div>
                       <span className="font-bold tracking-widest uppercase text-xs">Simulating Match...</span>
                    </div>
                  )}
                  {!matchInProgress && matchState.overs > 0 && (
                    <div className="text-center">
                      <p className="text-2xl font-bold mb-4">Final Result: {matchState.score > 50 ? 'WIN' : 'LOSS'}</p>
                      <button onClick={startMatch} className="px-8 py-3 bg-slate-700 rounded-full font-bold">Play Again</button>
                    </div>
                  )}
                </div>

