interface CustomizationHubProps {
    gameData: GameData;
    setGameData: React.Dispatch<React.SetStateAction<GameData | null>>;
}

const CustomizationHub: React.FC<CustomizationHubProps> = ({ gameData, setGameData }) => {
    const [selectedTeamId, setSelectedTeamId] = useState(gameData.userTeamId);

    const selectedTeam = gameData.allTeamsData.find(t => t.id === selectedTeamId)!;

    const updateTeam = (updates: Partial<TeamData>) => {
        setGameData(prev => {
            if (!prev) return null;
            const newTeamsData = prev.allTeamsData.map(t => t.id === selectedTeamId ? { ...t, ...updates } : t);
            // Sync with active teams as well
            const newTeams = prev.teams.map(t => t.id === selectedTeamId ? { ...t, name: updates.name || t.name } : t);
            return { ...prev, allTeamsData: newTeamsData, teams: newTeams };
        });
    };

    return (
        <div className="p-4 h-[calc(100vh-90px)] overflow-y-auto">
            <h2 className="text-2xl font-bold text-center mb-6">Customization Hub</h2>

            <div className="space-y-6">
                <section className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-md border border-gray-200 dark:border-gray-700">
                    <h3 className="text-sm font-bold text-teal-500 uppercase mb-4 tracking-widest">Team Branding</h3>

                    <div className="mb-4">
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Select Team to Edit</label>
                        <select 
                            value={selectedTeamId}
                            onChange={(e) => setSelectedTeamId(e.target.value)}
                            className="w-full p-2 rounded bg-gray-100 dark:bg-gray-900 border border-gray-300 dark:border-gray-700"
                        >
                            {gameData.allTeamsData.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                        </select>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Team Name</label>
                            <input 
                                type="text"
                                value={selectedTeam.name}
                                onChange={(e) => updateTeam({ name: e.target.value })}
                                className="w-full p-2 rounded bg-gray-100 dark:bg-gray-900 border border-gray-300 dark:border-gray-700"
                            />
                        </div>
                         <div>
                            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Primary Color (Hex)</label>
                            <div className="flex gap-2">
                                <input 
                                    type="color"
                                    value={selectedTeam.color}
                                    onChange={(e) => updateTeam({ color: e.target.value })}
                                    className="h-10 w-12 rounded border-0"
                                />
                                <input 
                                    type="text"
                                    value={selectedTeam.color}
                                    onChange={(e) => updateTeam({ color: e.target.value })}
                                    className="flex-grow p-2 rounded bg-gray-100 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-xs"
                                />
                            </div>
                        </div>
                    </div>

                    <div className="mt-4">
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Team Logo (SVG Code)</label>
                        <textarea 
                            value={selectedTeam.logo}
                            onChange={(e) => updateTeam({ logo: e.target.value })}
                            className="w-full h-32 p-2 rounded bg-gray-100 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 font-mono text-[10px]"
                            placeholder="Paste <svg>...</svg> here"
                        />
                    </div>

                    <div className="mt-6 p-4 bg-gray-100 dark:bg-gray-900 rounded-lg flex flex-col items-center">
                        <p className="text-[10px] text-gray-500 uppercase font-bold mb-2">Live Graphic Preview</p>
                        <div className="w-full h-12 rounded flex items-center px-4 overflow-hidden border shadow-inner" style={{ backgroundColor: selectedTeam.color }}>
                             <div className="w-8 h-8 mr-3" dangerouslySetInnerHTML={{ __html: selectedTeam.logo }}></div>
                             <span className="font-black italic text-white text-lg tracking-tighter uppercase drop-shadow-md">{selectedTeam.name}</span>
                        </div>
                    </div>
                </section>

                <section className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-md border border-gray-200 dark:border-gray-700">
                    <h3 className="text-sm font-bold text-purple-500 uppercase mb-4 tracking-widest">Scorecard Style</h3>
                    <p className="text-xs text-gray-500 mb-4">Graphics dynamically inherit colors from the batting team during live matches.</p>
                    <div className="grid grid-cols-2 gap-4">
                         <div className="p-4 bg-slate-900 rounded border-l-4 border-teal-500">
                            <span className="text-xs font-bold text-white uppercase tracking-tighter">BBL Standard</span>
                            <div className="h-1 w-full bg-teal-500 mt-1 opacity-50"></div>
                         </div>
                         <div className="p-4 bg-gray-800 rounded border-t-2 border-yellow-500">
                            <span className="text-xs font-bold text-white uppercase tracking-tighter">Classic HD</span>
                         </div>
                    </div>
