interface CustomizationHubProps {
    gameData: GameData;
    setGameData: React.Dispatch<React.SetStateAction<GameData | null>>;
}

const CustomizationHub: React.FC<CustomizationHubProps> = ({ gameData, setGameData }) => {
    const [selectedTeamId, setSelectedTeamId] = useState(gameData.userTeamId);

    const selectedTeam = gameData.allTeamsData.find(t => t.id === selectedTeamId)!;

    const updateTeam = (updates: Partial<TeamData>) => {
        setGameData(prev => {
            if (!prev) return null;
            const newTeamsData = prev.allTeamsData.map(t => t.id === selectedTeamId ? { ...t, ...updates } : t);
            const newTeams = prev.teams.map(t => t.id === selectedTeamId ? { ...t, name: updates.name || t.name } : t);
            return { ...prev, allTeamsData: newTeamsData, teams: newTeams };
        });
    };

    return (
        <div className="p-4 h-[calc(100vh-90px)] overflow-y-auto bg-slate-50 dark:bg-slate-950">
            <h2 className="text-3xl font-black text-center mb-8 tracking-tighter uppercase dark:text-white">Customization Center</h2>

            <div className="space-y-8">
                <section className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-800">
                    <div className="flex items-center gap-3 mb-6">
                        <div className="w-2 h-6 bg-teal-500 rounded-full"></div>
                        <h3 className="text-lg font-black uppercase tracking-tight dark:text-white">Franchise Branding</h3>
                    </div>

                    <div className="mb-6">
                        <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Select Team to Customize</label>
                        <select 
                            value={selectedTeamId}
                            onChange={(e) => setSelectedTeamId(e.target.value)}
                            className="w-full p-4 rounded-xl bg-slate-100 dark:bg-slate-800 border-none font-bold text-slate-800 dark:text-white focus:ring-2 focus:ring-teal-500"
                        >
                            {gameData.allTeamsData.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                        </select>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Official Team Name</label>
                            <input 
                                type="text"
                                value={selectedTeam.name}
                                onChange={(e) => updateTeam({ name: e.target.value })}
                                className="w-full p-4 rounded-xl bg-slate-100 dark:bg-slate-800 border-none font-bold text-slate-800 dark:text-white focus:ring-2 focus:ring-teal-500"
                            />
                        </div>
                         <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Primary Identity Color</label>
                            <div className="flex gap-3">
                                <input 
                                    type="color"
                                    value={selectedTeam.color}
                                    onChange={(e) => updateTeam({ color: e.target.value })}
                                    className="h-14 w-14 rounded-xl border-none p-0 overflow-hidden cursor-pointer"
                                />
                                <input 
                                    type="text"
                                    value={selectedTeam.color}
                                    onChange={(e) => updateTeam({ color: e.target.value })}
                                    className="flex-grow p-4 rounded-xl bg-slate-100 dark:bg-slate-800 border-none font-mono text-sm font-bold text-slate-800 dark:text-white"
                                />
                            </div>
                        </div>
                    </div>

                    <div className="mt-6">
                        <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Team Logo (SVG Format)</label>
                        <textarea 
                            value={selectedTeam.logo}
                            onChange={(e) => updateTeam({ logo: e.target.value })}
                            className="w-full h-40 p-4 rounded-xl bg-slate-100 dark:bg-slate-800 border-none font-mono text-[10px] text-slate-800 dark:text-teal-400 focus:ring-2 focus:ring-teal-500"
