                             <div className="absolute inset-0 bg-gradient-to-r from-black/20 to-transparent"></div>
                             <div className="w-10 h-10 mr-4 drop-shadow-lg relative z-10" dangerouslySetInnerHTML={{ __html: selectedTeam.logo }}></div>
