const StrategyToggle = ({ label, value, onChange }: { label: string, value: Strategy, onChange: (s: Strategy) => void }) => (
    <div className="flex flex-col bg-slate-800/80 backdrop-blur rounded-xl p-2 flex-1 border border-slate-700">
        <span className="text-[10px] text-slate-500 font-black uppercase mb-2 tracking-widest text-center">{label}</span>
        <div className="grid grid-cols-3 gap-1 bg-black/30 rounded-lg p-1">
            {(['defensive', 'balanced', 'attacking'] as Strategy[]).map(s => (
                <button
                    key={s}
                    onClick={() => onChange(s)}
                    className={`py-2 text-[9px] uppercase font-black rounded-md transition-all ${value === s 
                        ? 'bg-teal-500 text-white shadow-lg scale-105' 
                        : 'text-slate-500 hover:text-slate-300'}`}
                >
                    {s.slice(0,3)}
                </button>
            ))}
        </div>
    </div>
);

const LiveMatchScreen: React.FC<LiveMatchScreenProps> = ({ match, gameData, onMatchComplete, onExit, savedState }) => {
    const { state, playBall, playOver, autoSimulate, setBattingStrategy, setBowlingStrategy, selectOpeners, selectNextBatter, selectNextBowler } = useLiveMatch(match, gameData, onMatchComplete, savedState);
    const [lastBallFlash, setLastBallFlash] = useState<string | null>(null);

    useEffect(() => {
        if (state?.recentBalls.length) {
            setLastBallFlash(state.recentBalls[0]);
            const timer = setTimeout(() => setLastBallFlash(null), 1500);
            return () => clearTimeout(timer);
        }
    }, [state?.recentBalls]);

    if (!state) return <div className="h-full flex items-center justify-center bg-slate-950 text-white font-black animate-pulse">BOOTING CRICKET ENGINE...</div>;

    const { battingTeam, bowlingTeam, innings, currentInningIndex, currentBatters, currentBowlerId, recentBalls, commentary, target, waitingFor, strategies } = state;

    const battingTeamData = gameData.allTeamsData.find(t => t.id === battingTeam.id)!;
    const bowlingTeamData = gameData.allTeamsData.find(t => t.id === bowlingTeam.id)!;
    const sponsorship = gameData.sponsorships?.[gameData.currentFormat] || INITIAL_SPONSORSHIPS[gameData.currentFormat];

    const currentInning = innings[currentInningIndex];
    const striker = currentInning.batting.find(b => b.playerId === currentBatters.strikerId);
    const bowler = currentInning.bowling.find(b => b.playerId === currentBowlerId);

    return (
        <div className="h-full flex flex-col bg-slate-950 text-white overflow-hidden relative font-sans select-none">
            {/* --- TOP BROADCAST OVERLAY --- */}
