                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 flex items-center justify-center text-teal-400 opacity-80" dangerouslySetInnerHTML={{ __html: sponsorship.tvLogo || '' }} />
                    <div className="h-4 w-px bg-slate-700"></div>
                    <div className="flex flex-col">
                        <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em] leading-none">Premier Series</span>
                        <span className="text-xs font-black text-white italic uppercase tracking-tighter leading-none mt-1">{gameData.currentFormat}</span>
                    </div>
                </div>
                <button onClick={() => onExit(state)} className="px-4 py-1.5 rounded-full bg-red-600/10 border border-red-600/50 text-red-500 text-[10px] font-black uppercase tracking-widest hover:bg-red-600/20 transition-all">End Feed</button>
            </div>

            {/* --- SIMULATION ENGINE VIEW --- */}
            <div className="flex-1 relative flex items-center justify-center bg-slate-900 overflow-hidden">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_rgba(0,0,0,0)_0%,_rgba(0,0,0,0.9)_100%)] z-10"></div>
                <div className="absolute inset-0 opacity-10 pointer-events-none bg-[url('https://images.unsplash.com/photo-1540747913346-19e3adbd17c3?auto=format&fit=crop&w=1200&q=80')] bg-cover bg-center"></div>

                {/* Event VFX */}
                {lastBallFlash && (
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20 pointer-events-none animate-in zoom-in-50 duration-300">
                         <div className={`text-9xl font-black italic uppercase tracking-tighter drop-shadow-[0_0_40px_rgba(255,255,255,0.5)] ${lastBallFlash === 'W' ? 'text-red-500' : 'text-teal-400'}`}>
                            {lastBallFlash === 'W' ? 'OUT' : lastBallFlash === '4' ? 'FOUR' : lastBallFlash === '6' ? 'SIX' : ''}
                         </div>
                    </div>
                )}

                {/* --- REAL BROADCAST GRAPHIC (BOTTOM ANCHORED) --- */}
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-[95%] max-w-4xl z-30 drop-shadow-2xl">
                    {/* Main Bar */}
                    <div className="bg-slate-900/95 backdrop-blur-3xl rounded-xl border-b-8 shadow-2xl overflow-hidden flex flex-col md:flex-row h-auto md:h-16" style={{ borderColor: battingTeamData.color }}>

                        {/* LEFT: Batting Team & Score */}
                        <div className="flex items-stretch flex-shrink-0 border-r border-slate-800">
                             <div className="w-16 flex items-center justify-center p-2" style={{ backgroundColor: battingTeamData.color }}>
                                 <div className="w-full h-full text-white drop-shadow-md" dangerouslySetInnerHTML={{ __html: battingTeamData.logo }} />
                             </div>
                             <div className="px-5 flex flex-col justify-center bg-slate-800/20">
                                 <div className="text-[9px] font-black uppercase text-slate-500 tracking-widest leading-none mb-1.5">{battingTeamData.name}</div>
                                 <div className="text-3xl font-black italic tracking-tighter leading-none tabular-nums">
                                     {currentInning.score}<span className="text-slate-600 mx-0.5 font-normal">/</span>{currentInning.wickets}
                                 </div>
                             </div>
                        </div>

                        {/* MIDDLE: Overs & Context */}
                        <div className="flex-grow flex items-center px-6 gap-6 bg-gradient-to-r from-transparent to-slate-950/20">
                             <div className="flex flex-col">
                                 <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1.5">Overs</span>
                                 <span className="text-2xl font-black italic leading-none tabular-nums">{currentInning.overs}</span>
                             </div>

                             <div className="h-8 w-px bg-slate-800"></div>

                             <div className="flex-grow">
                                 {target ? (
                                     <div className="animate-in fade-in slide-in-from-left-2 duration-500">
                                         <div className="text-[10px] font-black text-teal-400 uppercase tracking-tighter mb-1">Chase Update</div>
                                         <div className="text-lg font-black uppercase tracking-tight leading-none italic">
                                             Need {target - currentInning.score + 1} <span className="text-xs text-slate-500 not-italic lowercase">runs from</span> {((gameData.currentFormat.includes('T20') ? 120 : 300) - currentInning.bowling.reduce((a,b)=>a+b.ballsBowled,0))} <span className="text-xs text-slate-500 not-italic lowercase">balls</span>
                                         </div>
                                     </div>
                                 ) : (
                                     <div className="flex flex-col justify-center">
                                         <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1.5">Match State</div>
                                         <div className="text-sm font-black uppercase tracking-tight text-white/90">First Innings Live</div>
                                     </div>
                                 )}
                             </div>
                        </div>

                        {/* RIGHT: Bowler Identity */}
                        <div className="flex items-stretch border-l border-slate-800 bg-slate-950/40">
                             <div className="px-5 flex flex-col justify-center items-end text-right">
                                 <div className="text-[9px] font-black uppercase text-slate-500 tracking-widest leading-none mb-1.5">Bowling</div>
                                 <div className="text-sm font-black uppercase tracking-tight leading-none">{bowler?.playerName}</div>
                                 <div className="text-xs font-black text-teal-500 mt-1 tabular-nums">{bowler?.wickets}-{bowler?.runsConceded} <span className="text-slate-600 font-normal">({bowler?.overs})</span></div>
                             </div>
                             <div className="w-16 flex items-center justify-center p-2 opacity-50" style={{ backgroundColor: bowlingTeamData.color }}>
                                 <div className="w-full h-full text-white" dangerouslySetInnerHTML={{ __html: bowlingTeamData.logo }} />
                             </div>
                        </div>
                    </div>

                    {/* Secondary Ticker Line */}
                    <div className="bg-black/60 backdrop-blur shadow-xl h-10 mt-1.5 rounded-lg flex items-center px-5 gap-8 border border-white/5 overflow-hidden">
                        <div className="flex items-center gap-3">
                             <div className="flex items-center justify-center w-5 h-5 rounded-md bg-teal-500/20 border border-teal-500/30">
                                 <div className="w-2 h-2 rounded-full bg-teal-500 animate-pulse"></div>
                             </div>
                             <span className="text-[10px] font-black text-slate-300 uppercase tracking-tighter">Batter: <span className="text-white italic">{striker?.playerName}</span> <span className="text-teal-400 ml-1">{striker?.runs}* <span className="text-slate-500 text-[8px]">({striker?.balls})</span></span></span>
                        </div>

                        <div className="hidden md:flex items-center gap-1.5 ml-auto">
                             <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest mr-2">Recent</span>
                             {recentBalls.slice(0, 6).reverse().map((b, i) => (
                                 <div key={i} className={`w-6 h-6 rounded-md flex items-center justify-center text-[10px] font-black border shadow-inner ${b === 'W' ? 'bg-red-600/20 border-red-500 text-red-500' : b === '4' || b === '6' ? 'bg-teal-500/20 border-teal-500 text-teal-400' : 'bg-slate-800/40 border-slate-700 text-slate-400'}`}>
                                    {b}
                                 </div>
                             ))}
                        </div>
                    </div>
                </div>
            </div>

            {/* --- INTERACTIVE CONTROLS --- */}
            <div className="bg-slate-900 border-t border-slate-800 p-6 z-50 shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
