                     <StrategyToggle label="Batting Strategy" value={strategies.batting} onChange={setBattingStrategy} />
                     <StrategyToggle label="Bowling Strategy" value={strategies.bowling} onChange={setBowlingStrategy} />
                </div>

                <div className="flex gap-3 max-w-4xl mx-auto">
                    <button onClick={playBall} className="flex-[3] bg-teal-600 hover:bg-teal-500 text-white font-black py-5 rounded-2xl text-xl shadow-2xl shadow-teal-500/20 active:scale-95 transition-all uppercase italic tracking-tighter">Play Ball</button>
                    <button onClick={playOver} className="flex-1 bg-slate-800 hover:bg-slate-700 text-white font-black py-5 rounded-2xl shadow-lg active:scale-95 transition-all uppercase text-sm tracking-widest">Over</button>
                    <button onClick={autoSimulate} className="flex-1 bg-indigo-600 hover:bg-indigo-500 text-white font-black py-5 rounded-2xl shadow-lg active:scale-95 transition-all uppercase text-sm tracking-widest">Auto</button>
                </div>
            </div>

            {/* Selection Overlays */}
            {waitingFor && (
                <div className="absolute inset-0 bg-black/80 z-[100] backdrop-blur-md flex items-center justify-center p-8 animate-in fade-in duration-300">
                    <div className="w-full max-w-md bg-slate-900 rounded-[2rem] p-8 border border-slate-800 shadow-[0_0_100px_rgba(0,0,0,0.8)]">
                        <div className="text-center mb-8">
                            <h3 className="text-3xl font-black uppercase italic tracking-tighter mb-2">New Selection</h3>
                            <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em]">Decision required: {waitingFor}</p>
                        </div>

                        <div className="space-y-3 max-h-80 overflow-y-auto pr-2 custom-scrollbar">
                            {(waitingFor === 'batter' ? currentInning.batting.filter(p=>!p.isOut) : currentInning.bowling).map(p => (
                                <button
                                    key={p.playerId}
                                    onClick={() => waitingFor === 'batter' ? selectNextBatter(p.playerId) : selectNextBowler(p.playerId)}
                                    className="w-full bg-slate-800 p-5 rounded-2xl text-left hover:bg-teal-900/30 border border-slate-700 hover:border-teal-500 transition-all flex justify-between items-center group"
                                >
                                    <span className="font-black uppercase tracking-tight text-white group-hover:text-teal-400">{p.playerName}</span>
                                    {waitingFor === 'bowler' && <span className="text-[10px] font-black text-slate-500 bg-black/40 px-2 py-1 rounded uppercase tracking-widest">{p.overs} Overs</span>}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

