import React from 'react';
import { GameData, Team, CareerScreen } from '../types';
import { Icons } from './Icons';
import { SPONSOR_THRESHOLDS, TOURNAMENT_LOGOS } from '../data';

interface DashboardProps {
    gameData: GameData;
    userTeam: Team | null;
    setScreen: (screen: CareerScreen) => void;
    handlePlayMatch: () => void;
    handleForwardDay: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ gameData, userTeam, setScreen, handlePlayMatch, handleForwardDay }) => {
    const currentSchedule = gameData.schedule[gameData.currentFormat];
    const matchIndex = gameData.currentMatchIndex[gameData.currentFormat];
    const sponsorship = gameData.sponsorships?.[gameData.currentFormat];
    const popularity = gameData.popularity || 0;
    const currentThresholds = SPONSOR_THRESHOLDS[gameData.currentFormat] || {};

    if (matchIndex >= currentSchedule.length) {
        return (
            <div className="p-8 text-center h-full flex flex-col items-center justify-center dark:bg-slate-950">
                <h2 className="text-4xl font-black italic uppercase tracking-tighter mb-4 dark:text-white">Tournament Ended</h2>
                <p className="text-slate-500 font-bold uppercase text-xs tracking-widest mb-8">All fixtures completed for the current format.</p>
                <button onClick={() => setScreen('AWARDS_RECORDS')} className="px-8 py-3 bg-teal-500 text-white font-black rounded-2xl uppercase tracking-tighter italic">View Final Records</button>
            </div>
        );
    }

    let nextMatch = { ...currentSchedule[matchIndex] };
    if (nextMatch.group !== 'Round-Robin') {
        const standings = gameData.standings[gameData.currentFormat];
        const getTeamName = (pos: number) => standings.length >= pos ? standings[pos - 1]?.teamName : `TBD ${pos}`;
        const resolvePlaceholder = (placeholder: string) => {
            if (['1st', '2nd', '3rd', '4th'].includes(placeholder)) return getTeamName(parseInt(placeholder[0], 10));
            return placeholder;
        };
        nextMatch.teamA = resolvePlaceholder(nextMatch.teamA);
        nextMatch.teamB = resolvePlaceholder(nextMatch.teamB);
    }

    const isUserMatch = userTeam ? (nextMatch.teamA === userTeam.name || nextMatch.teamB === userTeam.name) : false;
    const homeGround = gameData.grounds.find(g => g.code === gameData.allTeamsData.find(t => t.name === nextMatch.teamA)?.homeGround);

    const renderTournamentLogo = () => {
        if (sponsorship?.tournamentLogo) return <div className={`w-12 h-12 mx-auto mb-4 ${sponsorship.logoColor} drop-shadow-lg`} dangerouslySetInnerHTML={{__html: sponsorship.tournamentLogo}}></div>;
        return <div className="w-12 h-12 mx-auto mb-4 text-slate-700" dangerouslySetInnerHTML={{__html: TOURNAMENT_LOGOS[0].svg}}></div>;
    };

    return (
        <div className="p-6 space-y-6 dark:bg-slate-950 min-h-full pb-20">
            <header className="text-center py-6">
                <p className="text-[10px] font-black text-slate-500 dark:text-slate-400 tracking-[0.4em] mb-4 uppercase">Season 2026 • Match Centre</p>
                {renderTournamentLogo()}
                {sponsorship ? (
                     <h1 className={`text-4xl leading-none italic ${sponsorship.logoColor || 'text-teal-500'} drop-shadow-xl ${sponsorship.sponsorName === "Sike's" ? 'font-black tracking-tighter' : 'font-black uppercase tracking-tighter'}`}>
                        {sponsorship.sponsorName} <span className="text-slate-800 dark:text-white font-light not-italic italic underline decoration-white/20 underline-offset-8">{sponsorship.tournamentName}</span>
                    </h1>
                ) : (
                    <h1 className="text-3xl font-black italic tracking-tighter dark:text-white uppercase">{gameData.currentFormat}</h1>
                )}
            </header>

            <div className="bg-white dark:bg-slate-900 rounded-[2rem] p-8 shadow-2xl border border-slate-100 dark:border-slate-800 relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-2 h-full bg-teal-500"></div>
                <h3 className="font-black text-[10px] mb-6 text-slate-400 uppercase tracking-[0.3em]">Upcoming Encounter</h3>
                <div className="flex items-center justify-around mb-8">
                    <div className="flex flex-col items-center gap-3">
                         <div className="w-16 h-16 drop-shadow-md" dangerouslySetInnerHTML={{__html: gameData.allTeamsData.find(t => t.name === nextMatch.teamA)?.logo || ''}}></div>
                         <span className="font-black uppercase tracking-tighter text-sm max-w-[80px] text-center dark:text-white">{nextMatch.teamA}</span>
                    </div>
                    <div className="text-2xl font-black italic text-slate-200 dark:text-slate-800">VS</div>
                    <div className="flex flex-col items-center gap-3">
                         <div className="w-16 h-16 drop-shadow-md" dangerouslySetInnerHTML={{__html: gameData.allTeamsData.find(t => t.name === nextMatch.teamB)?.logo || ''}}></div>
                         <span className="font-black uppercase tracking-tighter text-sm max-w-[80px] text-center dark:text-white">{nextMatch.teamB}</span>
                    </div>
                </div>

                <div className="text-center mb-8">
                    <p className="text-xs font-bold text-slate-500 dark:text-slate-400 mb-1">{homeGround?.name || 'Grand Arena'}</p>
                    <p className="text-[10px] font-black text-teal-500 uppercase tracking-widest">{nextMatch.date}</p>
                </div>

                <button onClick={isUserMatch ? handlePlayMatch : handleForwardDay} className={`w-full font-black py-5 px-6 rounded-2xl shadow-2xl transition-all active:scale-95 text-lg uppercase italic tracking-tighter flex items-center justify-center gap-3 ${isUserMatch ? 'bg-teal-500 hover:bg-teal-400 text-white' : 'bg-slate-800 hover:bg-slate-700 text-white'}`}>
                    <Icons.PlayMatch />
                    <span>{isUserMatch ? 'Enter Match Feed' : 'Simulate Schedule'}</span>
                </button>
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 flex flex-col gap-1">
                    <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Team Budget</span>
                    <span className="text-2xl font-black text-teal-400 tabular-nums italic">$25.4M</span>
                </div>
                <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 flex flex-col gap-1" onClick={() => setScreen('SPONSOR_ROOM')}>
                    <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Popularity ★</span>
                    <span className="text-2xl font-black text-yellow-400 tabular-nums italic">{popularity}</span>
                </div>
            </div>

            <div className="grid grid-cols-3 gap-3">
                 {[
                    { s: 'LEAGUES', l: 'Table', i: Icons.Podium },
                    { s: 'LINEUPS', l: 'Squad', i: Icons.Lineups },
                    { s: 'TRANSFERS', l: 'Market', i: Icons.Transfers },
                    { s: 'EDITOR', l: 'Editor', i: Icons.Editor },
                    { s: 'COMPARISON', l: 'Analyze', i: Icons.Compare },
                    { s: 'NEWS', l: 'News', i: Icons.News }
                 ].map((item, idx) => (
                    <button key={idx} onClick={() => setScreen(item.s as any)} className="bg-white dark:bg-slate-900 p-4 rounded-2xl shadow-xl flex flex-col items-center gap-2 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all group">
                        <div className="text-slate-500 dark:text-slate-400 group-hover:scale-110 transition-transform group-hover:text-teal-500"><item.i /></div>
                        <span className="font-black text-[9px] uppercase tracking-widest dark:text-white">{item.l}</span>
                    </button>
                 ))}
            </div>
        </div>
    );
};

