                    className={`py-2 text-[9px] uppercase font-black rounded-md transition-all ${value === s 
                        ? 'bg-teal-500 text-white shadow-lg scale-105' 
                        : 'text-slate-500 hover:text-slate-300'}`}
                >
                    {s.slice(0,3)}
                </button>
            ))}
        </div>
    </div>
);

const LiveMatchScreen: React.FC<LiveMatchScreenProps> = ({ match, gameData, onMatchComplete, onExit, savedState }) => {
    const { state, playBall, playOver, autoSimulate, setBattingStrategy, setBowlingStrategy, selectOpeners, selectNextBatter, selectNextBowler, startMatch } = useLiveMatch(match, gameData, onMatchComplete, savedState);
    const [showScorecard, setShowScorecard] = useState(false);

    if (!state) return <div className="h-full flex items-center justify-center bg-slate-950 text-white">Initializing Engine...</div>;

    const { battingTeam, bowlingTeam, innings, currentInningIndex, currentBatters, currentBowlerId, recentBalls, commentary, target, waitingFor, strategies } = state;

    // Get team visual data
    const battingTeamData = gameData.allTeamsData.find(t => t.id === battingTeam.id)!;
    const bowlingTeamData = gameData.allTeamsData.find(t => t.id === bowlingTeam.id)!;
    const sponsorship = gameData.sponsorships?.[gameData.currentFormat] || INITIAL_SPONSORSHIPS[gameData.currentFormat];

    const currentInning = innings[currentInningIndex];
    const striker = currentInning.batting.find(b => b.playerId === currentBatters.strikerId);
    const nonStriker = currentInning.batting.find(b => b.playerId === currentBatters.nonStrikerId);
    const bowler = currentInning.bowling.find(b => b.playerId === currentBowlerId);

    const runRate = parseFloat(currentInning.overs) > 0 ? (currentInning.score / (Math.floor(parseFloat(currentInning.overs)) + (parseFloat(currentInning.overs)%1*1.666))).toFixed(2) : "0.00";

    return (
        <div className="h-full flex flex-col bg-slate-950 text-white overflow-hidden relative font-sans">
            {/* --- TOP BROADCAST BAR --- */}
            <div className="h-14 bg-gradient-to-r from-black/80 to-transparent flex items-center justify-between px-4 z-20">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 flex items-center justify-center" dangerouslySetInnerHTML={{ __html: sponsorship.tvLogo || '' }} />
                    <div className="h-6 w-px bg-slate-700"></div>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{gameData.currentFormat}</span>
                </div>
                <button onClick={() => onExit(state)} className="text-[10px] font-bold bg-red-600/20 text-red-500 border border-red-500/50 px-3 py-1 rounded-full uppercase">Exit</button>
            </div>

            {/* --- MAIN SIMULATION AREA --- */}
            <div className="flex-1 relative flex items-center justify-center bg-slate-900 overflow-hidden">
                {/* Background Stadium Ambience */}
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_rgba(0,0,0,0)_0%,_rgba(0,0,0,0.8)_100%)] z-10"></div>
                <div className="absolute inset-0 opacity-20 pointer-events-none bg-[url('https://images.unsplash.com/photo-1540747913346-19e3adbd17c3?auto=format&fit=crop&w=1200&q=80')] bg-cover bg-center"></div>

                {/* Event Flash */}
                {recentBalls.length > 0 && (
                    <div className="absolute top-1/3 left-1/2 -translate-x-1/2 z-20 flex flex-col items-center animate-bounce">
                         <div className={`text-6xl font-black italic uppercase tracking-tighter drop-shadow-[0_0_20px_rgba(255,255,255,0.5)] ${recentBalls[0] === 'W' ? 'text-red-500' : 'text-yellow-400'}`}>
                            {recentBalls[0] === 'W' ? 'OUT' : recentBalls[0] === '4' ? 'FOUR' : recentBalls[0] === '6' ? 'SIX' : ''}
                         </div>
                    </div>
                )}

                {/* --- BROADCAST GRAPHIC (BBL STYLE) --- */}
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-[90%] z-30 group">
                    {/* Themed Strip */}
                    <div className="bg-slate-900/90 backdrop-blur-xl rounded-lg border-b-4 shadow-2xl overflow-hidden flex h-14" style={{ borderColor: battingTeamData.color }}>
                        {/* Team Logo Section */}
                        <div className="w-14 h-full flex items-center justify-center p-2" style={{ backgroundColor: battingTeamData.color }}>
                            <div className="w-full h-full text-white" dangerouslySetInnerHTML={{ __html: battingTeamData.logo }} />
                        </div>

                        {/* Score Section */}
                        <div className="px-4 flex flex-col justify-center border-r border-slate-800 bg-slate-800/30">
                            <div className="text-[10px] font-black uppercase text-slate-500 leading-none mb-1">{battingTeamData.name}</div>
                            <div className="text-2xl font-black tabular-nums leading-none tracking-tighter">
                                {currentInning.score}<span className="text-slate-500 mx-0.5">/</span>{currentInning.wickets}
                            </div>
                        </div>

                        {/* Overs Section */}
                        <div className="px-4 flex flex-col justify-center border-r border-slate-800">
                            <div className="text-[10px] font-bold text-slate-500 uppercase leading-none mb-1">Overs</div>
                            <div className="text-xl font-bold tabular-nums leading-none">{currentInning.overs}</div>
                        </div>

                        {/* Match Context (Target/RRR) */}
                        <div className="flex-grow flex items-center px-4">
                            {target ? (
                                <div className="animate-fade-in">
                                    <span className="text-[10px] font-bold text-slate-500 uppercase block mb-0.5">Need {target - currentInning.score + 1} off {(gameData.currentFormat.includes('T20') ? 120 : 300) - currentInning.bowling.reduce((a,b)=>a+b.ballsBowled,0)} balls</span>
                                    <div className="flex gap-4">
                                        <span className="text-xs font-bold text-white">RRR: <span style={{ color: battingTeamData.color }}>{( (target - currentInning.score + 1) / Math.max(0.1, ( (gameData.currentFormat.includes('T20') ? 120 : 300) - currentInning.bowling.reduce((a,b)=>a+b.ballsBowled,0) ) / 6 )).toFixed(2)}</span></span>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest animate-pulse">Inning 1 Live</div>
                            )}
                        </div>

                        {/* Recent Balls */}
                        <div className="hidden md:flex items-center px-4 gap-1 border-l border-slate-800">
                             {recentBalls.slice(0, 6).reverse().map((b, i) => (
                                 <div key={i} className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black ${b === 'W' ? 'bg-red-600' : b === '4' || b === '6' ? 'bg-teal-500' : 'bg-slate-700'}`}>
                                    {b}
                                 </div>
                             ))}
                        </div>
                    </div>

                    {/* Secondary Themed Line */}
                    <div className="bg-slate-800/80 backdrop-blur-md h-8 mt-1 rounded-b-lg flex items-center px-4 gap-6">
                        <div className="flex items-center gap-2">
                             <span className="text-[9px] font-black text-slate-500 uppercase">Batter</span>
                             <span className="text-xs font-bold text-white">{striker?.playerName} <span className="text-slate-400 font-normal">{striker?.runs}({striker?.balls})</span></span>
                        </div>
                        <div className="flex items-center gap-2">
                             <span className="text-[9px] font-black text-slate-500 uppercase">Bowler</span>
                             <span className="text-xs font-bold text-white">{bowler?.playerName} <span className="text-slate-400 font-normal">{bowler?.wickets}-{bowler?.runsConceded}</span></span>
                        </div>
                        <div className="ml-auto flex gap-2">
                             <div className="w-2 h-2 rounded-full animate-pulse" style={{ backgroundColor: battingTeamData.color }}></div>
                             <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Live Feed</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* --- CONTROLS PANEL --- */}
            <div className="bg-slate-900 border-t border-slate-800 p-4 z-40">
                <div className="flex gap-4 mb-4">
                     <StrategyToggle label="Batting" value={strategies.batting} onChange={setBattingStrategy} />
                     <StrategyToggle label="Bowling" value={strategies.bowling} onChange={setBowlingStrategy} />
                </div>

                <div className="flex gap-2">
                    <button onClick={playBall} className="flex-[2] bg-teal-600 hover:bg-teal-500 text-white font-black py-4 rounded-xl text-lg shadow-lg shadow-teal-500/20 active:scale-95 transition-all">PLAY BALL</button>
                    <button onClick={playOver} className="flex-1 bg-slate-800 hover:bg-slate-700 text-white font-bold py-4 rounded-xl shadow-lg active:scale-95 transition-all">SKIP OVER</button>
                    <button onClick={autoSimulate} className="flex-1 bg-slate-800 hover:bg-slate-700 text-white font-bold py-4 rounded-xl shadow-lg active:scale-95 transition-all">AUTO</button>
                </div>
            </div>

            {/* Selection Modals */}
            {waitingFor && (
                <div className="absolute inset-0 bg-black/80 z-[100] backdrop-blur-sm flex items-center justify-center p-6">
                    <div className="w-full max-w-md bg-slate-800 rounded-2xl p-6 border border-slate-700 shadow-2xl">
                        <h3 className="text-xl font-bold mb-4 text-center">New {waitingFor === 'batter' ? 'Batter' : waitingFor === 'bowler' ? 'Bowler' : 'Openers'}</h3>
                        <p className="text-xs text-slate-400 text-center mb-6">Select from your squad to resume play.</p>

                        <div className="space-y-2">
                            {(waitingFor === 'batter' ? currentInning.batting.filter(p=>!p.isOut) : currentInning.bowling).map(p => (
                                <button
                                    key={p.playerId}
                                    onClick={() => waitingFor === 'batter' ? selectNextBatter(p.playerId) : selectNextBowler(p.playerId)}
                                    className="w-full bg-slate-900 p-4 rounded-xl text-left hover:bg-teal-900/30 border border-slate-700 hover:border-teal-500 transition-all flex justify-between items-center"
                                >
                                    <span className="font-bold">{p.playerName}</span>
                                    {waitingFor === 'bowler' && <span className="text-[10px] text-slate-500 uppercase">{p.overs} Overs</span>}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default LiveMatchScreen;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
